// // This D flip-flop captures the value of D on the falling edge of the clock and outputs it on Q. When the reset signal is low, the output Q is reset to 1.
module d_ff(
    input wire clk,
    input wire rst,
    input wire D,
    output reg Q
    );

always @(posedge clk or posedge rst) begin
    if (rst) begin
        Q <= 0;
    end else begin
        Q <= D;
    end
end

endmodule
